<title>SARAH - ACC Editor Novo</title>
<style>
:root{--bg:#0f172a;--panel:#111827;--panel2:#0b1220;--line:#334155;--text:#e5e7eb;--muted:#94a3b8;--accent:#38bdf8;--good:#166534;--danger:#991b1b;--warn:#92400e}
*{box-sizing:border-box}body{margin:0;font-family:Arial,Helvetica,sans-serif;background:var(--bg);color:var(--text)}.wrap{max-width:1800px;margin:0 auto;padding:18px}a{color:#93c5fd}h1{margin-bottom:6px}.grid{display:grid;grid-template-columns:430px 1fr;gap:18px}.panel{background:var(--panel);border:1px solid var(--line);border-radius:16px;padding:16px}.stack{display:flex;flex-direction:column;gap:12px}.row{display:grid;grid-template-columns:1fr 1fr;gap:10px}.searchRow{display:grid;grid-template-columns:1fr 140px 140px;gap:10px}.toolbar{display:flex;flex-wrap:wrap;gap:8px}label{display:block;font-size:12px;color:var(--muted);margin:0 0 6px}input,textarea,select,button{width:100%;font:inherit;border:1px solid var(--line);border-radius:10px}input,textarea,select{background:var(--panel2);color:var(--text);padding:10px 12px}textarea{min-height:90px;resize:vertical}button{cursor:pointer;padding:10px 14px;background:#1f2937;color:var(--text)}button.primary{background:var(--accent);color:#082f49;font-weight:700}button.good{background:var(--good)}button.danger{background:var(--danger)}button.warn{background:var(--warn)}.list{display:flex;flex-direction:column;gap:10px;max-height:330px;overflow:auto}.entry{border:1px solid var(--line);border-radius:14px;padding:12px;background:var(--panel2)}.entry.active{outline:2px solid var(--accent)}.entryTop{display:flex;justify-content:space-between;gap:10px;align-items:center}.assetGrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(155px,1fr));gap:12px;max-height:660px;overflow:auto}.assetCard{border:1px solid var(--line);border-radius:16px;padding:10px;background:var(--panel2);display:flex;flex-direction:column;gap:8px}.assetCard.selected{outline:2px solid var(--accent)}.assetThumb{height:112px;border:1px solid var(--line);border-radius:12px;background:#0f172a;display:flex;align-items:center;justify-content:center;overflow:hidden}.assetThumb svg{max-width:104px;max-height:104px}.assetName{font-weight:700;font-size:13px;line-height:1.3}.assetMeta{font-size:12px;color:var(--muted);line-height:1.3;word-break:break-word}.kpi{display:grid;grid-template-columns:repeat(5,1fr);gap:10px}.kpi .box{background:var(--panel2);border:1px solid var(--line);border-radius:12px;padding:10px}.kpi .n{font-size:24px;font-weight:700}.previewCard{display:flex;gap:16px;align-items:flex-start;border:1px solid var(--line);border-radius:18px;padding:18px;background:var(--panel2)}.iconBox{width:96px;height:96px;border-radius:18px;background:#0f172a;border:1px solid var(--line);display:flex;align-items:center;justify-content:center;overflow:hidden;font-size:36px}.iconBox svg{max-width:84px;max-height:84px}.codeBox{min-height:300px;background:#020617;color:#d1fae5;border:1px solid var(--line);padding:14px;border-radius:16px;font-family:Consolas,monospace;font-size:13px;line-height:1.5;white-space:pre;overflow:auto}.status{font-size:12px;color:#93c5fd}.muted{color:var(--muted)}.subgrid{display:grid;grid-template-columns:1fr;gap:18px}.small{font-size:12px;color:var(--muted)}code{background:#020617;padding:2px 6px;border-radius:6px}@media(max-width:1150px){.grid{grid-template-columns:1fr}.searchRow{grid-template-columns:1fr}.kpi{grid-template-columns:1fr 1fr}}
</style>
</head>
<body>
<div class="wrap">
<p><a href="dashboard.php">← Dashboard</a> · <a href="library_browser.php">Navegar biblioteca</a> · <b>EDITOR NOVO V2</b></p>
<h1>SARAH - ACC Editor Integrado V2</h1>
<p class="muted">Pesquisa direta de pictogramas no servidor. Esta versão não carrega os 7800 SVG de uma só vez.</p>
<div class="grid">
<div class="panel"><div class="stack">
<div class="row"><div><label>Versão</label><input id="versao" type="number" value="1"></div><div><label>Idioma</label><input id="idioma" value="pt-PT"></div></div>
<div class="row"><div><label>Voz: lang</label><input id="vozLang" value="pt-PT"></div><div><label>Voz: rate</label><input id="vozRate" type="text" value="1,0"></div></div>
<div><label>Voz: pitch</label><input id="vozPitch" type="text" value="1,0"></div>
<div class="toolbar"><button class="good" id="loadSeedBtn">Carregar seed.json do servidor</button><button class="primary" id="saveServerBtn">Publicar no servidor</button></div>
<div class="toolbar"><button class="primary" id="tabCatBtn">Editar categoria</button><button id="tabItemBtn">Editar item</button></div>
<div id="catForm"><div class="row"><div><label>ID da categoria</label><input id="catId" placeholder="comida"></div><div><label>Emoji</label><input id="catEmoji" placeholder="🍽️"></div></div><div><label>Nome da categoria</label><input id="catNome" placeholder="Comida"></div><div class="toolbar"><button class="primary" id="saveCategoriaBtn">Guardar categoria</button><button id="clearCategoriaBtn">Limpar</button><button class="warn" id="duplicateCategoriaBtn">Duplicar</button><button class="danger" id="deleteCategoriaBtn">Eliminar</button></div></div>
<div id="itemForm" style="display:none"><div class="row"><div><label>ID do item</label><input id="itemId" placeholder="quero_agua"></div><div><label>Categoria</label><select id="itemCategoria"></select></div></div><div><label>Texto / frase</label><textarea id="itemTexto" placeholder="Quero água."></textarea></div><div><label>Caminho do ícone</label><input id="itemIcone" placeholder="icons/agua.svg"></div><div class="row"><div><label>Pictograma selecionado</label><input id="selectedAssetPath" readonly placeholder="Nenhum pictograma selecionado"></div><div><label>&nbsp;</label><button id="applyAssetBtn">Aplicar pictograma ao item</button></div></div><div class="toolbar"><button class="primary" id="saveItemBtn">Guardar item</button><button id="clearItemBtn">Limpar</button><button class="warn" id="duplicateItemBtn">Duplicar</button><button class="danger" id="deleteItemBtn">Eliminar</button></div></div>
<div class="status" id="status">Pronto.</div>
</div></div>
<div class="subgrid">
<div class="panel"><div class="kpi"><div class="box"><div class="muted">Categorias</div><div class="n" id="kpiCategorias">0</div></div><div class="box"><div class="muted">Itens</div><div class="n" id="kpiItens">0</div></div><div class="box"><div class="muted">Pictogramas vistos</div><div class="n" id="kpiAssets">0</div></div><div class="box"><div class="muted">Em uso vistos</div><div class="n" id="kpiUsed">0</div></div><div class="box"><div class="muted">Em falta vistos</div><div class="n" id="kpiMissing">0</div></div></div></div>
<div class="panel"><h3>Categorias</h3><div class="list" id="categoriesList"></div></div>
<div class="panel"><h3>Itens</h3><div class="searchRow"><input id="itemSearch" placeholder="Procurar item..."><select id="itemFilterCategoria"><option value="">Todas as categorias</option></select><select id="itemMissingFilter"><option value="">Todos</option><option value="missing">Pictograma não visto</option><option value="ok">Pictograma visto</option></select></div><br><div class="list" id="itemsList"></div></div>
<div class="panel"><h3>Biblioteca visual de pictogramas no servidor</h3><div class="searchRow"><input id="assetSearch" placeholder="Escreve o nome: comer, agua, casa..."><button class="primary" id="assetSearchBtn">Pesquisar</button><button id="assetMoreBtn">Mais</button></div><p class="small">Pesquisa no servidor via <code>api/list_icons.php?q=...</code>.</p><div class="toolbar"><button id="quickComer">comer</button><button id="quickAgua">agua</button><button id="quickCasa">casa</button><button id="quickEscola">escola</button><button id="clearAssetsBtn">Limpar resultados</button></div><br><div class="assetGrid" id="assetGrid"></div></div>
<div class="panel"><h3>Pré-visualização</h3><div class="previewCard"><div class="iconBox" id="previewIcon">🖼️</div><div><div id="previewTitle" style="font-size:24px;font-weight:700;margin-bottom:8px">Nenhum item selecionado</div><div id="previewText" style="white-space:pre-wrap;line-height:1.5">Selecione ou crie um item.</div></div></div></div>
<div class="panel"><h3>JSON gerado</h3><div class="codeBox" id="jsonOut"></div></div>
</div></div></div>
<script>
const state={selectedCategory:null,selectedItem:null,selectedAssetPath:null,assetOffset:0,assetLimit:80,currentAssetQuery:'',assets:{},seed:{versao:1,idioma:'pt-PT',voz:{lang:'pt-PT',rate:1,pitch:1},categorias:[],itens:[]}};
const $=id=>document.getElementById(id);const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const validId=id=>/^[a-zA-Z0-9._-]+$/.test(id);function num(v){return Number(String(v??'1').replace(',','.'))||1}function setStatus(m){$('status').textContent=m}function debounce(fn,ms){let t;return(...a)=>{clearTimeout(t);t=setTimeout(()=>fn(...a),ms)}}
function syncMeta(){state.seed.versao=Number($('versao').value||1);state.seed.idioma=$('idioma').value.trim()||'pt-PT';state.seed.voz.lang=$('vozLang').value.trim()||'pt-PT';state.seed.voz.rate=num($('vozRate').value);state.seed.voz.pitch=num($('vozPitch').value)}
function renderAll(){syncMeta();updateCategorySelects();updateKPIs();renderCategories();renderItems();renderAssets();renderPreview();renderJSON()}
function updateCategorySelects(){const sels=[$('itemCategoria'),$('itemFilterCategoria')];const old=sels.map(s=>s.value);sels[0].innerHTML='';sels[1].innerHTML='<option value="">Todas as categorias</option>';state.seed.categorias.forEach(c=>{const label=`${c.emoji||''} ${c.nome||c.id} (${c.id})`;sels.forEach(s=>{const o=document.createElement('option');o.value=c.id;o.textContent=label;s.appendChild(o)})});old.forEach((v,i)=>{if(v===''||state.seed.categorias.some(c=>c.id===v))sels[i].value=v})}
function updateKPIs(){const used=new Set(state.seed.itens.map(i=>i.icone).filter(Boolean));const missing=state.seed.itens.filter(i=>i.icone&&!state.assets[i.icone]).length;$('kpiCategorias').textContent=state.seed.categorias.length;$('kpiItens').textContent=state.seed.itens.length;$('kpiAssets').textContent=Object.keys(state.assets).length;$('kpiUsed').textContent=[...used].filter(p=>!!state.assets[p]).length;$('kpiMissing').textContent=missing}
function fillCategoryForm(c){$('catId').value=c.id||'';$('catNome').value=c.nome||'';$('catEmoji').value=c.emoji||''}
function fillItemForm(it){$('itemId').value=it.id||'';$('itemTexto').value=it.texto||'';$('itemCategoria').value=it.categoria||'';$('itemIcone').value=it.icone||'';state.selectedAssetPath=state.assets[it.icone]?it.icone:null;$('selectedAssetPath').value=state.selectedAssetPath||''}
function clearCategory(){$('catId').value='';$('catNome').value='';$('catEmoji').value='';state.selectedCategory=null}
function clearItem(){$('itemId').value='';$('itemTexto').value='';$('itemIcone').value='';if($('itemCategoria').options.length)$('itemCategoria').selectedIndex=0;state.selectedItem=null;state.selectedAssetPath=null;$('selectedAssetPath').value=''}
function renderCategories(){const wrap=$('categoriesList');wrap.innerHTML='';if(!state.seed.categorias.length){wrap.innerHTML='<div class="muted">Sem categorias.</div>';return}state.seed.categorias.forEach(c=>{const count=state.seed.itens.filter(i=>i.categoria===c.id).length;const el=document.createElement('div');el.className='entry'+(state.selectedCategory===c.id?' active':'');el.innerHTML=`<div class="entryTop"><div><b>${esc(c.emoji)} ${esc(c.nome)}</b><div class="muted">${esc(c.id)} · ${count} item(ns)</div></div><button>Selecionar</button></div>`;el.querySelector('button').onclick=()=>{state.selectedCategory=c.id;fillCategoryForm(c);showCatForm();renderAll();setStatus('Categoria selecionada: '+c.id)};wrap.appendChild(el)})}
function renderItems(){const wrap=$('itemsList');wrap.innerHTML='';const term=$('itemSearch').value.trim().toLowerCase();const cat=$('itemFilterCategoria').value;const miss=$('itemMissingFilter').value;const items=state.seed.itens.filter(it=>{const txt=[it.id,it.texto,it.categoria,it.icone].join(' ').toLowerCase();const okTerm=!term||txt.includes(term);const okCat=!cat||it.categoria===cat;const has=!it.icone||!!state.assets[it.icone];const okMiss=!miss||(miss==='missing'?!has:has);return okTerm&&okCat&&okMiss});if(!items.length){wrap.innerHTML='<div class="muted">Sem itens para mostrar.</div>';return}items.forEach(it=>{const has=!!state.assets[it.icone];const el=document.createElement('div');el.className='entry'+(state.selectedItem===it.id?' active':'');el.innerHTML=`<div class="entryTop"><div><b>${esc(it.texto)}</b><div class="muted">${esc(it.id)} · ${esc(it.categoria)} · ${has?'pictograma visto':'pictograma não visto nesta pesquisa'}</div><div class="muted">${esc(it.icone)}</div></div><button>Selecionar</button></div>`;el.querySelector('button').onclick=()=>{state.selectedItem=it.id;fillItemForm(it);showItemForm();renderAll();setStatus('Item selecionado: '+it.id)};wrap.appendChild(el)})}
function renderAssets(){const wrap=$('assetGrid');wrap.innerHTML='';const assets=Object.values(state.assets);if(!assets.length){wrap.innerHTML='<div class="muted">Sem pictogramas para mostrar. Escreve um termo e clica em Pesquisar.</div>';return}const used=new Set(state.seed.itens.map(i=>i.icone).filter(Boolean));assets.forEach(a=>{const isUsed=used.has(a.path);const el=document.createElement('div');el.className='assetCard'+(state.selectedAssetPath===a.path?' selected':'');el.innerHTML=`<div class="assetThumb">${a.content||'🖼️'}</div><div class="assetName">${esc(a.name||a.fileName||a.path)}</div><div class="assetMeta">${esc(a.path)}</div><div class="assetMeta">${isUsed?'em uso':'livre'}</div><button class="primary">Escolher este pictograma</button>`;el.querySelector('button').onclick=()=>{state.selectedAssetPath=a.path;$('selectedAssetPath').value=a.path;$('itemIcone').value=a.path;renderAll();setStatus('Pictograma escolhido e aplicado: '+a.path)};wrap.appendChild(el)})}
function renderPreview(){const it=state.seed.itens.find(x=>x.id===state.selectedItem);const box=$('previewIcon');const liveIcon=$('itemIcone').value.trim();const asset=liveIcon?state.assets[liveIcon]:null;if(!it&&!$('itemTexto').value.trim()){box.innerHTML='🖼️';$('previewTitle').textContent='Nenhum item selecionado';$('previewText').textContent='Selecione ou crie um item.';return}$('previewTitle').textContent=$('itemTexto').value.trim()||(it?it.texto:'Item novo');$('previewText').textContent='Categoria: '+($('itemCategoria').value||'')+'\\nPictograma: '+liveIcon;if(asset)box.innerHTML=asset.content||'🖼️';else box.textContent='🖼️'}
function renderJSON(){$('jsonOut').textContent=JSON.stringify(state.seed,null,2)}
function showCatForm(){$('catForm').style.display='';$('itemForm').style.display='none';$('tabCatBtn').className='primary';$('tabItemBtn').className=''}function showItemForm(){$('catForm').style.display='none';$('itemForm').style.display='';$('tabCatBtn').className='';$('tabItemBtn').className='primary'}
function saveCategory(){const c={id:$('catId').value.trim(),nome:$('catNome').value.trim(),emoji:$('catEmoji').value.trim()};if(!c.id||!validId(c.id)||!c.nome)return setStatus('Categoria inválida.');const idx=state.seed.categorias.findIndex(x=>x.id===c.id);if(idx>=0)state.seed.categorias[idx]=c;else state.seed.categorias.push(c);state.selectedCategory=c.id;renderAll();setStatus('Categoria guardada.')}
function deleteCategory(){const id=$('catId').value.trim();if(!id)return;if(state.seed.itens.some(i=>i.categoria===id))return setStatus('Não é possível eliminar: existem itens nesta categoria.');state.seed.categorias=state.seed.categorias.filter(c=>c.id!==id);clearCategory();renderAll();setStatus('Categoria eliminada.')}
function duplicateCategory(){const id=$('catId').value.trim();const c=state.seed.categorias.find(x=>x.id===id);if(!c)return setStatus('Selecione uma categoria primeiro.');let newId=id+'_copia',n=2;while(state.seed.categorias.some(x=>x.id===newId))newId=id+'_copia_'+(n++);const copy={...c,id:newId,nome:c.nome+' cópia'};state.seed.categorias.push(copy);state.selectedCategory=newId;fillCategoryForm(copy);renderAll();setStatus('Categoria duplicada.')}
function saveItem(){const it={id:$('itemId').value.trim(),texto:$('itemTexto').value.trim(),categoria:$('itemCategoria').value,icone:$('itemIcone').value.trim()};if(!it.id||!validId(it.id)||!it.texto||!it.categoria||!it.icone)return setStatus('Item inválido.');const idx=state.seed.itens.findIndex(x=>x.id===it.id);if(idx>=0)state.seed.itens[idx]=it;else state.seed.itens.push(it);state.selectedItem=it.id;renderAll();setStatus('Item guardado.')}
function deleteItem(){const id=$('itemId').value.trim();if(!id)return;state.seed.itens=state.seed.itens.filter(i=>i.id!==id);clearItem();renderAll();setStatus('Item eliminado.')}function duplicateItem(){const id=$('itemId').value.trim();const it=state.seed.itens.find(x=>x.id===id);if(!it)return setStatus('Selecione um item primeiro.');let newId=id+'_copia',n=2;while(state.seed.itens.some(x=>x.id===newId))newId=id+'_copia_'+(n++);const copy={...it,id:newId,texto:it.texto+' cópia'};state.seed.itens.push(copy);state.selectedItem=newId;fillItemForm(copy);renderAll();setStatus('Item duplicado.')}
function applySelectedAsset(){if(!state.selectedAssetPath)return setStatus('Nenhum pictograma selecionado.');$('itemIcone').value=state.selectedAssetPath;$('selectedAssetPath').value=state.selectedAssetPath;renderPreview();renderJSON();setStatus('Pictograma aplicado ao item.')}
async function loadSeed(){try{setStatus('A carregar seed.json...');const res=await fetch('api/seed_api.php',{credentials:'same-origin',cache:'no-store'});if(!res.ok)throw new Error('HTTP '+res.status);const data=await res.json();const seed=data.seed||data;state.seed={versao:seed.versao||1,idioma:seed.idioma||'pt-PT',voz:seed.voz||{lang:'pt-PT',rate:1,pitch:1},categorias:Array.isArray(seed.categorias)?seed.categorias:[],itens:Array.isArray(seed.itens)?seed.itens:[]};$('versao').value=state.seed.versao;$('idioma').value=state.seed.idioma;$('vozLang').value=state.seed.voz.lang||'pt-PT';$('vozRate').value=String(state.seed.voz.rate||1).replace('.',',');$('vozPitch').value=String(state.seed.voz.pitch||1).replace('.',',');state.selectedCategory=state.seed.categorias[0]?.id||null;state.selectedItem=state.seed.itens[0]?.id||null;if(state.selectedCategory)fillCategoryForm(state.seed.categorias[0]);if(state.selectedItem)fillItemForm(state.seed.itens[0]);renderAll();setStatus('seed.json carregado.')}catch(e){setStatus('Erro a carregar seed.json: '+e.message)}}
async function saveServer(){try{syncMeta();setStatus('A publicar no servidor...');const res=await fetch('api/save_seed.php',{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/json'},body:JSON.stringify({seed:state.seed})});const out=await res.json().catch(()=>({}));if(!res.ok||out.ok===false)throw new Error(out.error||('HTTP '+res.status));setStatus('Publicado no servidor.')}catch(e){setStatus('Erro ao publicar: '+e.message)}}
async function searchAssets(reset=true){const q=$('assetSearch').value.trim();if(q.length<2)return setStatus('Escreve pelo menos 2 letras.');if(reset){state.assetOffset=0;state.currentAssetQuery=q;state.assets={}}try{setStatus('A pesquisar no servidor: '+q+'...');const url='api/list_icons.php?q='+encodeURIComponent(q)+'&offset='+state.assetOffset+'&limit='+state.assetLimit+'&_='+(Date.now());const res=await fetch(url,{credentials:'same-origin',cache:'no-store'});if(!res.ok)throw new Error('HTTP '+res.status);const data=await res.json();if(data.ok===false)throw new Error(data.error||'Erro na API');const arr=data.items||[];arr.forEach(a=>{state.assets[a.path]=a});state.assetOffset+=arr.length;renderAll();setStatus(`Encontrados/carregados: ${Object.keys(state.assets).length}. Digitalizados: ${data.scanned||0}.`)}catch(e){setStatus('Erro a pesquisar pictogramas: '+e.message)}}
function quick(q){$('assetSearch').value=q;searchAssets(true)}
$('loadSeedBtn').onclick=loadSeed;$('saveServerBtn').onclick=saveServer;$('tabCatBtn').onclick=showCatForm;$('tabItemBtn').onclick=showItemForm;$('saveCategoriaBtn').onclick=saveCategory;$('clearCategoriaBtn').onclick=()=>{clearCategory();renderAll()};$('duplicateCategoriaBtn').onclick=duplicateCategory;$('deleteCategoriaBtn').onclick=deleteCategory;$('saveItemBtn').onclick=saveItem;$('clearItemBtn').onclick=()=>{clearItem();renderAll()};$('duplicateItemBtn').onclick=duplicateItem;$('deleteItemBtn').onclick=deleteItem;$('applyAssetBtn').onclick=applySelectedAsset;$('itemSearch').oninput=renderItems;$('itemFilterCategoria').onchange=renderItems;$('itemMissingFilter').onchange=renderItems;$('assetSearchBtn').onclick=()=>searchAssets(true);$('assetMoreBtn').onclick=()=>searchAssets(false);$('assetSearch').addEventListener('keydown',e=>{if(e.key==='Enter')searchAssets(true)});$('assetSearch').oninput=debounce(()=>{if($('assetSearch').value.trim().length>=3)searchAssets(true)},700);$('clearAssetsBtn').onclick=()=>{state.assets={};state.assetOffset=0;state.selectedAssetPath=null;$('selectedAssetPath').value='';renderAll();setStatus('Resultados limpos.')};$('quickComer').onclick=()=>quick('comer');$('quickAgua').onclick=()=>quick('agua');$('quickCasa').onclick=()=>quick('casa');$('quickEscola').onclick=()=>quick('escola');['versao','idioma','vozLang','vozRate','vozPitch','itemTexto','itemIcone','itemCategoria'].forEach(id=>{$(id).addEventListener('input',()=>{renderPreview();renderJSON()});$(id).addEventListener('change',()=>{renderPreview();renderJSON()})});renderAll();loadSeed();
</script></body></html>
